import React, { useState, useRef, useEffect, useCallback } from "react";


// ── Persistent Storage Hook ───────────────────────────────────────────────────
// Wraps useState with localStorage sync. Data survives page refresh.
// Usage: const [value, setValue] = useLocalStorage('key', defaultValue)
function useLocalStorage(key, defaultValue) {
  const [state, setState] = React.useState(() => {
    try {
      const stored = localStorage.getItem(key);
      return stored !== null ? JSON.parse(stored) : defaultValue;
    } catch {
      return defaultValue;
    }
  });
  const setAndStore = React.useCallback((val) => {
    setState(prev => {
      const next = typeof val === 'function' ? val(prev) : val;
      try { localStorage.setItem(key, JSON.stringify(next)); } catch {}
      return next;
    });
  }, [key]);
  return [state, setAndStore];
}

// ── Clear all BLG stored data (dev utility, accessible from console) ──────────
if (typeof window !== 'undefined') {
  window.BLG_clearStorage = () => {
    Object.keys(localStorage).filter(k => k.startsWith('blg_')).forEach(k => localStorage.removeItem(k));
    console.log('BLG storage cleared. Reload to reset.');
  };
}

