function ExportModal({ onClose }) {
  const [format, setFormat] = useState("pdf");
  const [sections, setSections] = useState(
    Object.fromEntries(EXPORT_SECTIONS.map(s => [s.id, s.default]))
  );
  const [generating, setGenerating] = useState(false);
  const [done, setDone] = useState(false);

  const toggleSection = (id) => setSections(p => ({ ...p, [id]: !p[id] }));
  const selectedCount = Object.values(sections).filter(Boolean).length;

  const handleExport = async () => {
    setGenerating(true);
    try {
      await (format === "pdf" ? generatePDF(sections) : format === "excel" ? generateExcel(sections) : generatePPT(sections));
      setDone(true);
      setTimeout(() => { setDone(false); setGenerating(false); }, 2000);
    } catch (e) {
      console.error(e);
      setGenerating(false);
      alert("Export failed — check console for details.");
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <div>
            <div className="modal-title">Export Report</div>
            <div className="text-xs text-mono text-dim mt-4">BLG Portfolio Intelligence · {new Date().toLocaleDateString()}</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>✕</button>
        </div>

        <div className="modal-body">
          {generating ? (
            <div className="export-generating">
              {done ? (
                <>
                  <div style={{ fontSize: 48 }}>✅</div>
                  <div style={{ fontSize: 16, fontWeight: 700, color: C.green }}>Export Complete!</div>
                  <div className="text-xs text-mono text-dim">Check your downloads folder</div>
                </>
              ) : (
                <>
                  <div className="export-spinner" />
                  <div style={{ fontSize: 14, fontWeight: 600, color: C.text }}>Generating {format.toUpperCase()}...</div>
                  <div className="text-xs text-mono text-dim">Building {selectedCount} section{selectedCount !== 1 ? "s" : ""}</div>
                </>
              )}
            </div>
          ) : (
            <>
              {/* Format selector */}
              <div className="text-xs text-mono text-dim mb-12" style={{ letterSpacing: ".1em", textTransform: "uppercase" }}>Select Format</div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginBottom: 20 }}>
                {EXPORT_FORMATS.map(f => (
                  <div
                    key={f.id}
                    className={`export-option ${format === f.id ? f.selectedClass : ""}`}
                    onClick={() => setFormat(f.id)}
                  >
                    {format === f.id && (
                      <div className="export-check" style={{ background: f.accentColor, color: C.bg }}>✓</div>
                    )}
                    <div className="export-option-icon">{f.icon}</div>
                    <div className="export-option-label" style={{ color: format === f.id ? f.accentColor : C.text }}>{f.label}</div>
                    <div className="export-option-sub">{f.sub}</div>
                  </div>
                ))}
              </div>

              {/* Section selector */}
              <div className="flex items-center justify-between mb-12">
                <div className="text-xs text-mono text-dim" style={{ letterSpacing: ".1em", textTransform: "uppercase" }}>Sections to Include</div>
                <div className="flex gap-8">
                  <button className="btn btn-ghost btn-sm" style={{ fontSize: 10 }} onClick={() => setSections(Object.fromEntries(EXPORT_SECTIONS.map(s => [s.id, true])))}>All</button>
                  <button className="btn btn-ghost btn-sm" style={{ fontSize: 10 }} onClick={() => setSections(Object.fromEntries(EXPORT_SECTIONS.map(s => [s.id, false])))}>None</button>
                </div>
              </div>
              <div className="section-select">
                {EXPORT_SECTIONS.map(s => (
                  <div key={s.id} className="section-check-row" onClick={() => toggleSection(s.id)}>
                    <div className={`checkbox ${sections[s.id] ? "checked" : ""}`}>{sections[s.id] ? "✓" : ""}</div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 12, fontWeight: 600, color: sections[s.id] ? C.text : C.textMid }}>{s.label}</div>
                      <div className="text-xs text-dim mt-4">{s.desc}</div>
                    </div>
                  </div>
                ))}
              </div>
            </>
          )}
        </div>

        {!generating && (
          <div className="modal-footer">
            <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
            <button
              className={`btn ${format === "pdf" ? "btn-primary" : format === "excel" ? "btn-secondary" : "btn-gold"}`}
              style={format === "excel" ? { background: "rgba(0,229,160,.15)", color: C.green, border: `1px solid rgba(0,229,160,.3)` } : {}}
              onClick={handleExport}
              disabled={selectedCount === 0}
            >
              {format === "pdf" ? "📄" : format === "excel" ? "📋" : "📊"} Export {format.toUpperCase()} ({selectedCount} sections)
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

