const BLG_RECS = COMM_RECORDS.filter(r => r.paidTo === 'BLG');
const RM_RECS  = COMM_RECORDS.filter(r => r.paidTo === 'Reignmaker');
const AD_RECS  = COMM_RECORDS.filter(r => r.distributor === 'AppDirect');
const TEL_RECS = COMM_RECORDS.filter(r => r.distributor === 'Telarus');

// ── Monthly rollup ───────────────────────────────────────────────────────────
const COMM_MO = COMM_MONTHS.reduce((acc, m) => {
  acc[m] = {
    total:  COMM_RECORDS.reduce((s,r) => s+(r.monthly[m]||0), 0),
    blg:    BLG_RECS.reduce((s,r)     => s+(r.monthly[m]||0), 0),
    rm:     RM_RECS.reduce((s,r)      => s+(r.monthly[m]||0), 0),
    ad:     AD_RECS.reduce((s,r)      => s+(r.monthly[m]||0), 0),
    telBlg: COMM_RECORDS.filter(r=>r.distributor==='Telarus'&&r.paidTo==='BLG').reduce((s,r)=>s+(r.monthly[m]||0),0),
    telRm:  COMM_RECORDS.filter(r=>r.distributor==='Telarus'&&r.paidTo==='Reignmaker').reduce((s,r)=>s+(r.monthly[m]||0),0),
  };
  return acc;
}, {});

